" Simple CDS View for material analytics
@Analytics.dataCategory: #FACT
@VDM.viewType: #CONSUMPTION
define view entity Z_MAT_STOCK_ANALYSIS
  as select from matdoc
{
  plant        as Plant,
  material     as Material,
  @Semantics.quantity.unitOfMeasure: 'BaseUnit'
  quantity     as StockQty,
  baseunit     as BaseUnit
}

" RAP: Behavior Definition skeleton
behavior for Z_Travel_Entity alias Travel
implementation in class zbp_travel unique
{
  create;
  update;
  delete;
  validation validateDates on save { field begin_date, end_date; }
  determination setStatus on modify { field status; }
}
